#include <stdio.h>
void bin(int n) {
    if (n > 1) bin(n / 2);
    printf("%d", n % 2);
}
int main() {
    int n;
    scanf("%d", &n);
    if (n == 0) printf("0");
    else bin(n);
    printf("\n");
    return 0;
}
